// Solution
function maxConsecutiveSublistSum(arr) {
  let maxSum = -Infinity;
  let currentSum = -Infinity;
  for (let i = 0; i < arr.length; i++) {
    currentSum = Math.max(arr[i], currentSum + arr[i]);
    maxSum = Math.max(maxSum, currentSum);
  }
  return maxSum === -Infinity ? -1 : maxSum;
}

