class Solution:
  def maxConsecutiveSublistSum(self, arr: List[int]) -> int:
    maxSum = float('-inf');
    currentSum = float('-inf');
    for num in arr:
      currentSum = max(num, currentSum + num);
      maxSum = max(maxSum, currentSum);
    return -1 if maxSum == float('-inf') else maxSum;
